func NewRootWorkflowValueMust(attributeTypes map[string]attr.Type, attributes map[string]attr.Value) RootWorkflowValue {
	object, diags := NewRootWorkflowValue(attributeTypes, attributes)

	if diags.HasError() {
		// This could potentially be added to the diag package.
		diagsStrings := make([]string, 0, len(diags))

		for _, diagnostic := range diags {
			diagsStrings = append(diagsStrings, fmt.Sprintf(
				"%s | %s | %s",
				diagnostic.Severity(),
				diagnostic.Summary(),
				diagnostic.Detail()))
		}

		panic("NewRootWorkflowValueMust received error(s): " + strings.Join(diagsStrings, "\n"))
	}

	return object
}

func (t RootWorkflowType) ValueFromTerraform(ctx context.Context, in tftypes.Value) (attr.Value, error) {
	if in.Type() == nil {
		return NewRootWorkflowValueNull(), nil
	}

	if !in.Type().Equal(t.TerraformType(ctx)) {
		return nil, fmt.Errorf("expected %s, got %s", t.TerraformType(ctx), in.Type())
	}

	if !in.IsKnown() {
		return NewRootWorkflowValueUnknown(), nil
	}

	if in.IsNull() {
		return NewRootWorkflowValueNull(), nil
	}

	attributes := map[string]attr.Value{}

	val := map[string]tftypes.Value{}

	err := in.As(&val)

	if err != nil {
		return nil, err
	}

	for k, v := range val {
		a, err := t.AttrTypes[k].ValueFromTerraform(ctx, v)

		if err != nil {
			return nil, err
		}

		attributes[k] = a
	}

	return NewRootWorkflowValueMust(RootWorkflowValue{}.AttributeTypes(ctx), attributes), nil
}

